TriggerOraclev10g.body:
DECLARE
  v_session_user VARCHAR2(128 CHAR);
BEGIN
  v_session_user := SYS_CONTEXT('USERENV', 'SESSION_USER');
  IF INSERTING THEN
    IF :NEW.created_at IS NULL THEN
      :NEW.created_at := SYSTIMESTAMP;
    END IF;
    IF :NEW.updated_at IS NULL THEN
      :NEW.updated_at := :NEW.created_at;
    END IF;
    IF :NEW.created_by IS NULL THEN
      :NEW.created_by := v_session_user;
    END IF;
    IF :NEW.updated_by IS NULL THEN
      :NEW.updated_by := NVL(:NEW.created_by, v_session_user);
    END IF;
  ELSE
    :NEW.created_at := :OLD.created_at;
    :NEW.created_by := :OLD.created_by;
    :NEW.updated_at := SYSTIMESTAMP;
    :NEW.updated_by := v_session_user;
    IF :OLD.is_deleted = 'N' AND :NEW.is_deleted = 'Y' THEN
      IF :NEW.deleted_at IS NULL THEN
        :NEW.deleted_at := SYSTIMESTAMP;
      END IF;
      IF :NEW.deleted_by IS NULL THEN
        :NEW.deleted_by := v_session_user;
      END IF;
    END IF;
  END IF;
END;
